    rrect(g, 14, 30, 40, 48, 3, P.yel);                   // cab (shade)
    rrect(g, 14, 30, 38, 47, 3, P.yel);
    rect(g, 15, 30, 40, 32, P.org);                       // cab trim
    stroke(g, [[38, 40], [50, 26], [56, 34]], 2.4, 2, P.org); // digging arm
    tri(g, 52, 32, 60, 34, 55, 42, P.lgy);                // bucket
